.vertical-navbox {
	width: 22em;
	float: right;
	clear: right;
	margin: 0 0 1em 1em;
	background: #f8f9fa;
	border: 1px solid #aaa;
	padding: 0.2em;
	border-spacing: 0.4em 0;
	text-align: center;
	line-height: 1.4em;
	font-size: 88%;
}

.sidebar-left {
	float: left;
	clear: left;
	margin: 0 1em 1em 0;
}

.sidebar-none {
	float: none;
	clear: both;
	margin: 0 1em 1em 0;
}

